{"name":"IncreaseLightBrightness","cron":"","period":100,"code":"prev_motion = false
while true {
  motion = (#MotionSensor).motionsensor_motion()
  if (motion && !prev_motion) {
    current_brightness = (#Light).light_currentbrightness()
    if (current_brightness < 100) {
      (#Light).light_movetobrightness(current_brightness + 10)
    }
  }
  prev_motion = motion
  delay(100)
}"}

